import React, { useEffect, useState } from "react";
import { useParams, Link } from "react-router-dom";
import Navbar from "../components/Navbar";
import { getFieldById } from "../services/api";

function FieldDetail() {
  const { id } = useParams();
  const [field, setField] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    const fetchField = async () => {
      try {
        const data = await getFieldById(id);
        setField(data);
      } catch (err) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };

    fetchField();
  }, [id]);

  return (
    <div>
      <Navbar />

      <div className="container page-section">
        {loading && <p>Đang tải chi tiết sân...</p>}
        {error && <p className="error-text">{error}</p>}

        {field && (
          <div className="simple-card">
            <h1 className="section-title">{field.name}</h1>
            <p className="section-subtitle">
              Xem thông tin chi tiết và chọn khung giờ phù hợp để đặt sân.
            </p>

            <div style={{ display: "grid", gap: "14px", marginTop: "20px" }}>
              <p className="field-info">
                <strong>Tên sân:</strong> {field.name}
              </p>

              <p className="field-info">
                <strong>Giá thuê:</strong> {field.price} VNĐ / giờ
              </p>

              <p className="field-info">
                <strong>Khu vực:</strong> {field.location || "Chưa cập nhật"}
              </p>

              <p className="field-info">
                <strong>Trạng thái:</strong>{" "}
                {field.status === "available" ? "Còn trống" : field.status}
              </p>
            </div>

            <div style={{ marginTop: "24px", display: "flex", gap: "12px" }}>
              <Link to="/fields" className="btn-outline">
                Quay lại danh sách sân
              </Link>

              <Link to={`/booking/${field.id}`} className="btn-primary">
                Đặt sân ngay
              </Link>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default FieldDetail;
